DROP TABLE gallery_folders;
CREATE TABLE gallery_folders (id int NOT NULL AUTO_INCREMENT, name varchar(100) NOT NULL, parent_id int, path varchar(500) NOT NULL, created_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (id), INDEX idx_parent (parent_id), INDEX idx_path (path)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE gallery_images;
CREATE TABLE gallery_images (id int NOT NULL AUTO_INCREMENT, folder_id int NOT NULL, filename varchar(255) NOT NULL, original_name varchar(255) NOT NULL, caption text, uploaded_at timestamp DEFAULT current_timestamp() NULL, uploaded_by int NOT NULL, PRIMARY KEY (id), INDEX uploaded_by (uploaded_by), INDEX idx_folder (folder_id), INDEX idx_uploaded_at (uploaded_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE leave_of_absence;
CREATE TABLE leave_of_absence (id int NOT NULL AUTO_INCREMENT, user_id int NOT NULL, start_date datetime NOT NULL, end_date datetime NOT NULL, reason text NOT NULL, superior_id int, status enum('pending','approved','denied') DEFAULT 'pending', submitted_at datetime DEFAULT current_timestamp(), reviewed_by int, reviewed_at datetime, review_notes text, PRIMARY KEY (id), INDEX superior_id (superior_id), INDEX reviewed_by (reviewed_by), INDEX idx_user_dates (user_id, start_date, end_date), INDEX idx_status (status), INDEX idx_dates (start_date, end_date)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=utf8mb4_unicode_ci;
DROP TABLE medals;
CREATE TABLE medals (id int NOT NULL AUTO_INCREMENT, name varchar(100) NOT NULL, description text NOT NULL, color varchar(7) DEFAULT '#FFD700', icon varchar(50) DEFAULT 'đź?…', created_at timestamp DEFAULT current_timestamp() NULL, created_by int, PRIMARY KEY (id), INDEX created_by (created_by), INDEX idx_name (name)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE modpack_mods;
CREATE TABLE modpack_mods (id int NOT NULL AUTO_INCREMENT, modpack_id int NOT NULL, workshop_id bigint NOT NULL COMMENT 'Steam Workshop file ID', display_name varchar(300) NOT NULL COMMENT 'Name from the HTML file initially, updated from Steam', steam_name varchar(300) COMMENT 'Official name from Steam API', file_size bigint DEFAULT 0 COMMENT 'Size in bytes from Steam API', icon_url varchar(500) COMMENT 'Preview image URL from Steam API', steam_url varchar(500) NOT NULL COMMENT 'Full Steam Workshop URL', is_indexed tinyint(1) DEFAULT 0, indexed_at timestamp NULL, PRIMARY KEY (id), INDEX idx_modpack (modpack_id), INDEX idx_workshop (workshop_id), INDEX idx_indexed (is_indexed)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE modpacks;
CREATE TABLE modpacks (id int NOT NULL AUTO_INCREMENT, name varchar(200) NOT NULL, description text, file_path varchar(500) NOT NULL COMMENT 'Path to the original uploaded .html file', created_by int NOT NULL, created_at timestamp DEFAULT current_timestamp() NULL, updated_at timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, mod_count int DEFAULT 0, total_size bigint DEFAULT 0 COMMENT 'Total size in bytes', index_status enum('pending','indexing','completed','failed') DEFAULT 'pending', index_progress int DEFAULT 0 COMMENT 'Number of mods indexed so far', index_error text COMMENT 'Error message if indexing failed', PRIMARY KEY (id), INDEX idx_name (name), INDEX idx_created_by (created_by), INDEX idx_status (index_status)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE operation_attendance;
CREATE TABLE operation_attendance (id int NOT NULL AUTO_INCREMENT, operation_id int NOT NULL, user_id int NOT NULL, status enum('present','tentative','absent') DEFAULT 'tentative' NOT NULL, updated_at timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, PRIMARY KEY (id), CONSTRAINT unique_attendance UNIQUE (operation_id, user_id), INDEX idx_operation (operation_id), INDEX idx_user (user_id), INDEX idx_status (status)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE operation_news;
CREATE TABLE operation_news (id int NOT NULL AUTO_INCREMENT, operation_id int NOT NULL, content text NOT NULL, posted_by int NOT NULL, posted_at timestamp DEFAULT current_timestamp() NULL, updated_at timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, PRIMARY KEY (id), INDEX idx_operation (operation_id), INDEX idx_posted_at (posted_at), INDEX posted_by (posted_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE operations;
CREATE TABLE operations (id int NOT NULL AUTO_INCREMENT, title varchar(200) NOT NULL, description text, banner_url varchar(500) DEFAULT '/images/operations/default-banner.jpg', created_by int NOT NULL, host_id int, discord_forum_post_id varchar(255), discord_thread_id varchar(255), created_at timestamp DEFAULT current_timestamp() NULL, updated_at timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, is_published tinyint(1) DEFAULT 1, orbat_template_id int, modpack_id int, orbat_type enum('none','fixed','dynamic') DEFAULT 'none', operation_type enum('main','side') DEFAULT 'main' NOT NULL, discord_message_id varchar(255), start_time int(10), end_time int(10), orbat_published tinyint(1) DEFAULT 1 NOT NULL, PRIMARY KEY (id), INDEX idx_created_by (created_by), INDEX fk_operation_orbat_template (orbat_template_id), INDEX idx_operation_host (host_id), INDEX idx_discord_thread (discord_thread_id), INDEX idx_operation_type (operation_type), INDEX fk_operation_modpack (modpack_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE orbat_assignments;
CREATE TABLE orbat_assignments (id int NOT NULL AUTO_INCREMENT, role_id int NOT NULL, user_id int NOT NULL, assigned_by int, assigned_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (id), CONSTRAINT unique_role_assignment UNIQUE (role_id), INDEX idx_role (role_id), INDEX idx_user (user_id), INDEX assigned_by (assigned_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE orbat_roles;
CREATE TABLE orbat_roles (id int NOT NULL AUTO_INCREMENT, squad_id int NOT NULL, role_name varchar(100) NOT NULL, display_order int DEFAULT 0, created_at timestamp DEFAULT current_timestamp() NULL, is_editor tinyint(1) DEFAULT 0 NOT NULL COMMENT 'If TRUE, the user assigned to this role can manage assignments within this squad', team_id int, PRIMARY KEY (id), INDEX idx_squad (squad_id), INDEX idx_order (display_order), INDEX fk_orbat_roles_team (team_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE orbat_squads;
CREATE TABLE orbat_squads (id int NOT NULL AUTO_INCREMENT, orbat_id int, operation_id int, name varchar(100) NOT NULL, display_order int DEFAULT 0, color varchar(7) DEFAULT '#3498DB', created_at timestamp DEFAULT current_timestamp() NULL, parent_squad_id int, PRIMARY KEY (id), INDEX idx_orbat (orbat_id), INDEX idx_operation (operation_id), INDEX idx_order (display_order), INDEX fk_orbat_squads_parent (parent_squad_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE orbat_teams;
CREATE TABLE orbat_teams (id int NOT NULL AUTO_INCREMENT, squad_id int NOT NULL, name varchar(100) NOT NULL, color varchar(20) DEFAULT '#6b8e23' NOT NULL, display_order int DEFAULT 0 NOT NULL, PRIMARY KEY (id), INDEX squad_id (squad_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE orbat_templates;
CREATE TABLE orbat_templates (id int NOT NULL AUTO_INCREMENT, name varchar(100) NOT NULL, description text, created_by int NOT NULL, created_at timestamp DEFAULT current_timestamp() NULL, updated_at timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, is_active tinyint(1) DEFAULT 1, PRIMARY KEY (id), INDEX idx_name (name), INDEX created_by (created_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE roster_members;
CREATE TABLE roster_members (id int NOT NULL AUTO_INCREMENT, discord_id varchar(50) NOT NULL, discord_username varchar(100) NOT NULL, discord_global_name varchar(100), discord_avatar varchar(255), nickname varchar(100), highest_role_id int, joined_at timestamp NULL, last_synced timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, is_visible tinyint(1) DEFAULT 1, PRIMARY KEY (id), CONSTRAINT discord_id UNIQUE (discord_id), INDEX idx_discord_id (discord_id), INDEX idx_highest_role (highest_role_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
