DROP TABLE user_medals;
CREATE TABLE user_medals (id int NOT NULL AUTO_INCREMENT, user_id int NOT NULL, medal_id int NOT NULL, awarded_by int NOT NULL, awarded_at timestamp DEFAULT current_timestamp() NULL, notes text, PRIMARY KEY (id), CONSTRAINT unique_user_medal UNIQUE (user_id, medal_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE user_trainings;
CREATE TABLE user_trainings (id int NOT NULL AUTO_INCREMENT, user_id int NOT NULL, training_id int NOT NULL, synced_at timestamp DEFAULT current_timestamp() NULL, last_verified timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, PRIMARY KEY (id), CONSTRAINT unique_user_training UNIQUE (user_id, training_id), INDEX idx_user (user_id), INDEX idx_training (training_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE users;
CREATE TABLE users (id int NOT NULL AUTO_INCREMENT, username varchar(50) NOT NULL, password_hash varchar(255), is_admin tinyint(1) DEFAULT 0, discord_id varchar(50), discord_username varchar(100), discord_global_name varchar(100), discord_avatar varchar(255), discord_access_token varchar(500), discord_refresh_token varchar(500), auth_type enum('local','discord') DEFAULT 'local', created_at timestamp DEFAULT current_timestamp() NULL, last_login timestamp NULL, PRIMARY KEY (id), CONSTRAINT username UNIQUE (username), CONSTRAINT discord_id UNIQUE (discord_id), INDEX idx_username (username), INDEX idx_discord_id (discord_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE zeus_permissions;
CREATE TABLE zeus_permissions (id int NOT NULL AUTO_INCREMENT, user_id int NOT NULL, has_zeus_role tinyint(1) DEFAULT 0, last_synced timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, PRIMARY KEY (id), CONSTRAINT user_id UNIQUE (user_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
