DROP VIEW active_loas;
CREATE ALGORITHM=UNDEFINED DEFINER=`u10_j9Ao1Ok2TF`@`%` SQL SECURITY DEFINER VIEW active_loas (id, user_id, start_date, end_date, reason, superior_id, status, submitted_at, reviewed_by, reviewed_at, review_notes, username, discord_global_name, discord_avatar, superior_username, superior_display_name) AS select `loa`.`id` AS `id`,`loa`.`user_id` AS `user_id`,`loa`.`start_date` AS `start_date`,`loa`.`end_date` AS `end_date`,`loa`.`reason` AS `reason`,`loa`.`superior_id` AS `superior_id`,`loa`.`status` AS `status`,`loa`.`submitted_at` AS `submitted_at`,`loa`.`reviewed_by` AS `reviewed_by`,`loa`.`reviewed_at` AS `reviewed_at`,`loa`.`review_notes` AS `review_notes`,`u`.`username` AS `username`,`u`.`discord_global_name` AS `discord_global_name`,`u`.`discord_avatar` AS `discord_avatar`,`sup`.`username` AS `superior_username`,`sup`.`discord_global_name` AS `superior_display_name` from ((`leave_of_absence` `loa` join `users` `u` on(`loa`.`user_id` = `u`.`id`)) left join `users` `sup` on(`loa`.`superior_id` = `sup`.`id`)) where `loa`.`status` = 'approved' and `loa`.`start_date` <= current_timestamp() and `loa`.`end_date` >= current_timestamp();
